","position":"FWD","naturalPosition":"FWD","rating":47},{"id":"4a69966a-8c5e-42bb-9a0b-082b6e6f8d43","name":"David Horák","position":"DEF","naturalPosition":"DEF","rating":40},{"id":"4aad4f2e-906f-4031-8416-40ffab922993","name":"Lukáš Pokorný","position":"DEF","naturalPosition":"DEF","rating":36},{"id":"05bb79de-d928-4203-944e-5e3cc9879a8e","name":"Matěj Černý","position":"FWD","naturalPosition":"FWD","rating":48},{"id":"df051873-4839-40e5-9155-9cb2730ac051","name":"Lukáš Marek","position":"MID","naturalPosition":"MID","rating":43},{"id":"327a8ccb-c486-425e-84cc-53d8680a4384","name":"Martin Král","position":"FWD","naturalPosition":"FWD","rating":32},{"id":"93d95066-aeef-4b9a-8f0c-f1ae97c9669d","name":"Tomáš Marek","position":"DEF","naturalPosition":"DEF","rating":34},{"id":"e58f1b6f-33bd-429a-8aa7-5bde233cc9b0","name":"Tomáš Novotný","position":"MID","naturalPosition":"MID","rating":40},{"id":"3d1c68d8-ef52-4507-ab8a-7025e0f24c96","name":"Jakub Procházka","position":"GK","naturalPosition":"GK","rating":6}],"subs":[{"id":"a78d9320-aa48-4690-bfd8-ddc676854603","name":"Ondřej Pokorný","position":"DEF","naturalPosition":"DEF","rating":30},{"id":"0ceb72c6-6d68-481f-a26a-56a4c878ca39","name":"David Veselý","position":"MID","naturalPosition":"MID","rating":29},{"id":"fdac2cab-33b9-4684-a5ea-074e5d0ac80a","name":"Michal Procházka","position":"MID","naturalPosition":"MID","rating":35},{"id":"58e8f9d4-4582-43a5-bc97-4c01691a3f9b","name":"Filip Jelínek","position":"MID","naturalPosition":"MID","rating":35}]}','[{"name":"Ondřej Kopecký","reason":"Kocovina","smsText":"Včera jsme to s klukama trochu přetáhli... omlouvám se"},{"name":"Jakub Novák","reason":"Práce","smsText":"Mám pohovor, nemůžu přijít"},{"name":"Tomáš Černý","reason":"Zdraví","smsText":"Mám ten zánět šlach zas, doktor říkal klid"},{"name":"Matěj Vlček","reason":"Osobní","smsText":"Zapomněl jsem, myslel jsem že hrajeme příští týden"},{"name":"David Pospíšil","reason":"Osobní","smsText":"Musím pomoct stěhovat kamarádovi, slíbil jsem to už třikrát"},{"name":"Filip Dvořák","reason":"Jiné","smsText":"Svědek na svatbě bratrance, nemůžu odmítnout"},{"name":"Lukáš Pospíšil","reason":"Práce","smsText":"Šéf mě poslal na extra jízdu, nemohl jsem odmítnout"},{"name":"Martin Procházka","reason":"Práce","smsText":"Inventura, musím počítat zboží"},{"name":"Tomáš Novotný","reason":"Zdraví","smsText":"Kotník mi otekl, asi jsem si ho podvrtl v práci"},{"name":"Jan Novák","reason":"Práce","smsText":"Mám brigádu v McDonaldu, nemůžu si vzít volno"}]');
