5-44a3-8a1f-3607ea80693b","name":"Jakub Beneš","position":"FWD","naturalPosition":"FWD","rating":26},{"id":"3bab3e7a-ac55-4c87-a0d0-1cf852def9b9","name":"Jan Svoboda","position":"FWD","naturalPosition":"FWD","rating":14}],"subs":[{"id":"a1ed6faa-ee19-4303-9e1c-cfe31bfcddf0","name":"Pavel Novotný","position":"MID","naturalPosition":"MID","rating":11},{"id":"7a950a3d-8dab-4325-b005-4951012f0114","name":"Jan Němec","position":"MID","naturalPosition":"MID","rating":19},{"id":"1dd9e8cc-4110-4c2d-88b1-f1486e9ee6b0","name":"Filip Růžička","position":"DEF","naturalPosition":"DEF","rating":14},{"id":"a0d64678-2328-4eef-9183-198bce4c2e03","name":"Jakub Marek","position":"FWD","naturalPosition":"FWD","rating":12},{"id":"98731260-55c7-4716-96e1-1ffd8fb7b9df","name":"Ondřej Marek","position":"DEF","naturalPosition":"DEF","rating":10}]}','[{"name":"Jan Fiala","reason":"Osobní","smsText":"Musím na rodičák do školky"},{"name":"Jakub Hájek","reason":"Práce","smsText":"Musím dodělat rozvody, jinak lidi nebudou mít proud"},{"name":"Lukáš Novotný","reason":"Práce","smsText":"Mám zkoušku zítra, musím se učit"},{"name":"Ondřej Sedláček","reason":"Práce","smsText":"Šéf mě nemůže uvolnit, je plno"},{"name":"David Marek","reason":"Osobní","smsText":"Zapomněl jsem, myslel jsem že hrajeme příští týden"},{"name":"Ondřej Němec","reason":"Osobní","smsText":"Ženská mi dala ultimátum — buď fotbal nebo ona. Ještě přemýšlím"},{"name":"Jan Němec","reason":"Jiné","smsText":"Spadl mi strom na plot a utečou slepice"},{"name":"Ondřej Růžička","reason":"Práce","smsText":"Utekla mi koza, honím ji po vsi"},{"name":"Jan Marek","reason":"Osobní","smsText":"Nemám odvoz, auto je v servisu od pátku"}]');
