":45,"type":"card","playerId":103,"playerName":"Ondřej Novák","teamId":2,"description":"Žlutá karta pro Ondřej Novák","detail":"yellow"},{"minute":45,"type":"special","playerId":3,"playerName":"Jan Marek","teamId":1,"description":"Poločas 2:1","detail":"half_time"},{"minute":46,"type":"chance","playerId":5,"playerName":"Jakub Novák","teamId":1,"description":"Šance! Jakub Novák — chytil brankář","detail":"chytil brankář"},{"minute":46,"type":"special","playerId":107,"playerName":"Pavel Kučera","teamId":2,"description":"Pavel Kučera chytá střelu","detail":"save"},{"minute":50,"type":"foul","playerId":103,"playerName":"Ondřej Novák","teamId":2,"description":"Faul Ondřej Novák"},{"minute":54,"type":"special","playerId":1,"playerName":"Jan Němec","teamId":1,"description":"Meteor Žirovnice kombinují přes střed hřiště.","detail":"possession"},{"minute":59,"type":"chance","playerId":110,"playerName":"Jan Veselý","teamId":2,"description":"Šance! Jan Veselý — zblokováno","detail":"zblokováno"},{"minute":59,"type":"special","playerId":12,"playerName":"Jan Němec","teamId":1,"description":"Jan Němec zblokoval šanci","detail":"block"},{"minute":62,"type":"foul","playerId":111,"playerName":"Martin Černý","teamId":2,"description":"Faul Martin Černý"},{"minute":62,"type":"card","playerId":111,"playerName":"Martin Černý","teamId":2,"description":"Žlutá karta pro Martin Černý","detail":"yellow"},{"minute":62,"type":"injury","playerId":110,"playerName":"Jan Veselý","teamId":2,"description":"Jan Veselý — naraženina","detail":"naraženina"},{"minute":62,"type":"substitution","playerId":113,"playerName":"Jakub Veselý","teamId":2,"description":"Střídání: Jakub Veselý za Jan Veselý"},{"minute":63,"type":"chance","playerId":111,"playerName":"Martin Černý","teamId":2,"description":"Šance! Martin Černý — vedle","detail":"vedle"},{"minute":65,"type":"foul","playerId":6,"playerName":"Lukáš Novák","teamId":1,"description":"Faul Lukáš Novák"},{"minute":67,"type":"special","playerId":5,"playerName":"Jakub Novák","teamId":1,"description":"Tvrdý pressing Meteor Žirovnice, TJ Kamenice nad Lipou se nemůžou dostat z vlastní půlky.","detail":"possession"},{"minute":68,"type":"injury","playerId":105,"playerName":"Lukáš Pospíšil","teamId":2,"description":"Lukáš Pospíšil — natažený sval","detail":"natažený sval"},{"minute":68,"type":"substitution","playerId":114,"playerName":"Jan Novotný","teamId":2,"description":"Střídání: Jan Novotný za Lukáš Pospíšil"},{"minute":74,"type":"special","playerId":102,"playerName":"David Němec","teamId":2,"description":"Divák u lajny komentuje situaci lépe než trenér","detail":"crowd"},{"minute":75,"type":"special","playerId":9,"playerName":"Vojtěch Svoboda","teamId":1,"description":"Hra se přesouvá na polovinu TJ Kamenice nad Lipou.","detail":"possession"},{"minute":79,"type":"special","playerId":1,"playerName":"Jan Němec","teamId":1,"description":"Hra se přesouvá na polovinu TJ Kamenice nad Lipou.","detail":"possession"},{"minute":82,"type":"special","playerId":1,"playerName":"Jan Němec","teamId":1,"description":"Hra se přesouvá na polovinu TJ Kamenice nad Lipou.","detail":"possession"},{"minute":87,"type":"special","playerId":6,"playerName":"Lukáš Novák","teamId":1,"description":"TJ Kamenice nad Lipou stahují obranu, Meteor Žirovnice hledají prostor.","detail":"possession"},{"minute":88,"type":"foul","playerId":108,"playerName":"Jakub Kučera","teamId":2,"description":"Faul Jakub Kučera"},{"minute":88,"type":"special","playerId":7,"playerName":"Lukáš Novotný","teamId":1,"description":"Meteor Žirovnice si nahrávají na polovině soupeře.","detail":"possession"},{"minute":89,"type":"foul","playerId":8,"playerName":"Tomáš Novák","teamId":1,"description":"Faul Tomáš Novák"},{"minute":90,"type":"special","playerId":1,"playerName":"Jan Němec","teamId":1,"description":"Meteor Žirovnice kombinují přes střed hřiště.","detail":"possession"},{"minute":90,"type":"special","playerId":4,"playerName":"Matěj Pokorný","teamId":1,"description":"Konec zápasu! Meteor Žirovnice 2:1 TJ Kamenice nad Lipou","detail":"full_time"}]','["1'' — Tomáš Novák měl prázdnou bránu, ale kopačka mu sklouzla. Smůla.","1'' — TJ Kamenice nad Lipou se snaží zrychlit. Zatím marně.","2'' — Brankář pustil míč pod rukama a Jan Němec to dopíchl do prázdné.","2'' — Asistence: Ondřej Novotný","5'' — Hra se přesouvá na polovinu soupeře.","6'' — Ondřej Novotný měl prázdnou bránu, ale kopačka mu sklouzla. Smůla.","6'' — Začalo pršet. Polovina diváků utekla pod střechu hospody.","6'' — Rozehrávka od brankáře. TJ Kamenice nad Lipou začínají znovu.","7'' — Rohový kop pro TJ Kamenice nad Lipou. Všichni běží do vápna.","9'' — Od plotu se ozývá: ''Rozhodčí, na oči!''","11'' — Martin Černý to tam prostě hodil. Nic hezkého, ale funguje to.","12'' — Meteor Žirovnice rotují míč ze strany na stranu. Soupeř běhá.","13'' — Nudný pasáž hry. Ani jedna strana nechce riskovat.","15'' — David Němec zastavil průnik soupeře. Ne zrovna čistě.","15'' — David Němec dostal žlutou. Z lavičky se ozývá: ''Za co?!''","16'' — Brankář fantasticky zasahuje po ráně Martin Černý! Co to bylo za zákrok!","17'' — Jan Novotný zkusil nůžky! Amatérské, ale ambiciózní. Mimo.","17'' — TJ Kamenice nad Lipou drží míč. Soupeř čeká na chybu.","18'' — Sousedka z okna volá: ''Tak co, vedeme?''","20'' — Meteor Žirovnice hrají na jistotu. Míč koluje v obraně.","23'' — Správce hřiště běží s houbou a studenou vodou. Filip Dvořák si drží koleno.","23'' — Střídání — Tomáš Procházka se konečně dočkal. Sedel na lavičce od začátku.","26'' — Meteor Žirovnice mají míč. Zatím nic nebezpečného.","30'' — TJ Kamenice nad Lipou se snaží zrychlit. Zatím marně.","32'' — Jakub Novák si zpracoval míč na hrudi a hledá řešení.","35'' — Jakub Novák zkusil nůžky! Amatérské, ale ambiciózní. Mimo.","35'' — Meteor Žirovnice kombinují přes střed hřiště.","38'' — Rozehrávka od brankáře. TJ Kamenice nad Lipou začínají znovu.","43'' — Tomáš Novák si zpracoval míč na hrudi a hledá řešení.","44'' — Jan Novotný sedí na trávníku a čeká na nosítka. Tedy na dva chlapy s dekou.","44'' — Taktická změna — Jan Němec jde na plac.","45'' — GÓÓÓL! Jakub Novák to tam napálil! Děda Vašek se probudil a zeptal se, co se stalo.","45'' — Asistence: Lukáš Novotný","45'' — Ondřej Novák držel soupeře za dres. Tak jednoduchý faul.","45'' — Žlutá karta! Ondřej Novák si to mohl odpustit.","45'' — Poločas! U stánku je guláš za padesátku a pivo za třicet.","46'' — Jakub Novák se dostal do gólové pozice, ale míč mu ujel z nohy.","46'' — TJ Kamenice nad Lipou rotují míč ze strany na stranu. Soupeř běhá.","50'' — Zbytečný faul Ondřej Novák třicet metrů od branky.","54'' — Meteor Žirovnice pomalu budují útok. Trpělivá hra.","59'' — Šance! Jan Veselý to trefil do brankáře z pěti metrů. To se neodpouští.","59'' — Aut pro Meteor Žirovnice. Chvíle na vydechnutí.","62'' — Strkanice po faulu Martin Černý. Rozhodčí uklidňuje situaci.","62'' — Martin Černý dostal žlutou. Z lavičky se ozývá: ''Za co?!''","62'' — Jan Veselý se srazil se spoluhráčem. Oba leží. Kdo koho?","62'' — Střídání: Jakub Veselý jde na hřiště. Čerstvá krev!","63'' — Martin Černý zkouší lob přes brankáře — míč letí nad. Škoda.","65'' — Lukáš Novák podrazil protihráče. Rozhodčí to viděl.","67'' — Meteor Žirovnice kontrolují tempo hry.","68'' — Lukáš Pospíšil sedí na trávníku a čeká na nosítka. Tedy na dva chlapy s dekou.","68'' — Trenér stahuje unavené hráče. Na hřiště jde Jan Novotný.","74'' — Někdo hodil na hřiště rohlík. Asi protest.","75'' — Meteor Žirovnice tlačí dopředu. Obrana soupeře má plné ruce práce.","79'' — Nudný pasáž hry. Ani jedna strana nechce riskovat.","82'' — Meteor Žirovnice drží míč. Soupeř čeká na chybu.","87'' — Meteor Žirovnice pomalu budují útok. Trpělivá hra.","88'' — Jakub Kučera se vrhl do skluzu — trefil hráče i míč. Rozhodčí píská.","88'' — Aut pro Meteor Žirovnice. Chvíle na vydechnutí.","89'' — Tomáš Novák se vrhl do skluzu — trefil hráče i míč. Rozhodčí píská.","90'' — Meteor Žirovnice se snaží najít mezeru v obraně.","90'' — Konec zápasu! Obě mužstva míří do hospody na rozbor."]','{"7527affb-6990-436e-bdea-f40fefe4408c":7.5,"ff38752f-cf30-4f94-886d-47ec1e646361":7.3,"cfa1fc2b-e089-4f19-87b2-cbf9baeb4bb7":6.7,"ef8159dc-cd5d-46ee-a795-5411b08a76e2":6.7,"c59ea0aa-b772-4484-ac69-9fcbd40e91e3":7.7,"dde5150e-53ba-463b-a11c-d4cad7c72fc7":6.4,"aa2a82d3-98eb-4222-827c-98ee14394360":7,"3728334c-1bf6-4d07-9a06-8fadc1c19657":6.6,"38468ac4-092b-4547-bdb7-e2d37ae20846":6.5,"a8290acf-1fe8-4d53-840a-94463194f47b":6.6,"dbce7890-7025-4e63-b73b-21276ec39d9d":6.3,"33fb480f-e987-4760-bb5c-c6ee2ef290ff":7,"8093260f-1515-4ab9-b99c-694f391e2a90":6,"56446167-c015-49cf-93af-f227ac6eb578":6,"e2e02df3-cc75-4428-83c1-f5fd88d78790":6.2,"58b03aa1-ab5c-4f13-8486-b161b1ed31a0":6,"e63bcb24-9fbd-4020-bd7b-32a18744a5d0":5.8,"f9246872-62f1-4268-a215-deb506a53d2e":5.1,"5374c828-a4fb-47fb-995b-cdc18ae9fb4f":4.9,"61c5ac2b-3540-41d7-9bd3-1d0b4d435ced":6.2,"8a7182f4-7cea-4ada-b078-e253e26b2c85":5.4,"4bc81421-b31c-4686-b73e-ff80633672c3":6.2,"2fc1c1df-faaa-4314-9612-cd9b121b2f10":6.3,"3c2e831c-26f8-4a78-9253-6a8c26de5514":5.6,"4a60de3b-8e40-4022-8dfa-8e7d146094f3":5.7,"f4423816-36b1-41ab-94ff-ceccb18c76ef":5.5,"081f8de6-6ed4-4b2e-a9d8-ed85fadd1469":6.2,"dea6eb71-2320-46e8-844a-73f46e3334df":5.7,"6ec715a9-0df7-44a9-b765-e2c99f7b853f":5.7,"02b2a6ab-ae2a-4f27-b3fb-4708d97479ba":5.9,"80dba8d5-560b-4138-8b2f-a17b84bb6a4b":6.2,"6f48e741-7126-4538-8b63-2513bfa99d8e":6}','2026-04-01 16:01:02','2026-03-31 21:36:23',NULL,NULL,29,NULL,50,'sunny','{"starters":[{"id":"7527affb-6990-436e-bdea-f40fefe4408c","name":"Jan Němec","position":"FWD","naturalPosition":"FWD","rating":28},{"id":"ff38752f-cf30-4f94-886d-47ec1e646361","name":"Ondřej Novotný","position":"DEF","naturalPosition":"DEF","rating":18},{"id":"cfa1fc2b-e089-4f19-87b2-cbf9baeb4bb7","name":"Jan Marek","position":"GK","naturalPosition":"GK","rating":3},{"id":"ef8159dc-cd5d-46ee-a795-5411b08a76e2","name":"Matěj Pokorný","position":"DEF","naturalPosition":"DEF","rating":18},{"id":"