ion"},{"minute":67,"type":"special","playerId":2,"playerName":"Jakub Černý","teamId":1,"description":"Jakub Černý rozehrává z hloubky pole.","detail":"possession"},{"minute":71,"type":"special","playerId":2,"playerName":"Jakub Černý","teamId":1,"description":"Slovan Pacov kontrolují tempo hry.","detail":"possession"},{"minute":74,"type":"special","playerId":10,"playerName":"Jan Pokorný","teamId":1,"description":"Slovan Pacov si nahrávají na polovině soupeře.","detail":"possession"},{"minute":75,"type":"substitution","playerId":114,"playerName":"Adam Novotný","teamId":2,"description":"Taktické střídání: Adam Novotný za Jakub Veselý"},{"minute":75,"type":"special","playerId":10,"playerName":"Jan Pokorný","teamId":1,"description":"Sokol Košetice stahují obranu, Slovan Pacov hledají prostor.","detail":"possession"},{"minute":76,"type":"special","playerId":10,"playerName":"Jan Pokorný","teamId":1,"description":"Slovan Pacov si nahrávají na polovině soupeře.","detail":"possession"},{"minute":80,"type":"special","playerId":10,"playerName":"Jan Pokorný","teamId":1,"description":"Jan Pokorný rozehrává z hloubky pole.","detail":"possession"},{"minute":81,"type":"foul","playerId":9,"playerName":"David Hájek","teamId":1,"description":"Faul David Hájek"},{"minute":82,"type":"goal","playerId":9,"playerName":"David Hájek","teamId":1,"description":"Gól! David Hájek skóruje","detail":"6:2"},{"minute":82,"type":"assist","playerId":1,"playerName":"Jan Pospíšil","teamId":1,"description":"Asistence: Jan Pospíšil","detail":""},{"minute":82,"type":"special","playerId":4,"playerName":"Jakub Horák","teamId":1,"description":"Tvrdý pressing Slovan Pacov, Sokol Košetice se nemůžou dostat z vlastní půlky.","detail":"possession"},{"minute":87,"type":"special","playerId":107,"playerName":"Jan Novák","teamId":2,"description":"Sokol Košetice si nahrávají na polovině soupeře.","detail":"possession"},{"minute":88,"type":"foul","playerId":5,"playerName":"Jan Procházka","teamId":1,"description":"Faul Jan Procházka"},{"minute":89,"type":"chance","playerId":107,"playerName":"Jan Novák","teamId":2,"description":"Šance! Jan Novák — břevno","detail":"břevno"},{"minute":90,"type":"special","playerId":7,"playerName":"Filip Hájek","teamId":1,"description":"Konec zápasu! Slovan Pacov 6:2 Sokol Košetice","detail":"full_time"}]','["1'' — Jan Pokorný to tam prostě hodil. Nic hezkého, ale funguje to.","1'' — Asistence: Jakub Černý","2'' — Filip Procházka sám před brankářem — a brankář chytá! Výborný zákrok!","4'' — David Marek sám před brankářem — a brankář chytá! Výborný zákrok!","5'' — Přímý kop po faulu Jan Procházka. Soupeř se zvedá ze země.","6'' — Dělovka od Jan Pokorný! Brankář ani nehnul rukama. To letělo jak z praku.","6'' — Asistence: Filip Hájek","8'' — Martin Jelínek držel soupeře za dres. Tak jednoduchý faul.","16'' — Jakub Černý posílá míč na druhou stranu. Přepínání hry.","17'' — Slovan Pacov kontrolují tempo hry.","19'' — Hra se přesouvá na polovinu soupeře.","21'' — Slovan Pacov se snaží zrychlit. Zatím marně.","24'' — Centr od Lukáš Dvořák — nikdo se k němu nedostal.","26'' — Slovan Pacov pomalu budují útok. Trpělivá hra.","28'' — Jan Procházka pálí z voleje — těsně mimo! To byla paráda i tak.","30'' — No tak Jan Procházka se trefil. Upřímně, ani on tomu nevěří.","30'' — Asistence: Jakub Horák","31'' — Jan Černý to tam doslova dotlačil. Nebyla to krása, ale je to gól.","37'' — Jan Pokorný přihrává do běhu spoluhráči. Dobré načasování.","39'' — Jan Procházka nahrává do středu — míč se vrací do obrany.","40'' — Jan Procházka sám před brankářem — a brankář chytá! Výborný zákrok!","45'' — Tvrdý zákrok David Hájek. To bolelo.","45'' — David Hájek se po žluté kartě tváří překvapeně. Jako by nevěděl.","45'' — Trenér si při kraji hřiště zapálil cigaretu. Asi ho to stresuje.","53'' — Slovan Pacov kontrolují tempo hry.","54'' — David Marek vede míč po křídle. Hledá přihrávku.","55'' — Šance! Jan Procházka to trefil do brankáře z pěti metrů. To se neodpouští.","55'' — Jakub Černý přihrává do běhu spoluhráči. Dobré načasování.","56'' — Parádní akce! Jan Pokorný si to obhodil a uklidil to k tyči!","56'' — Asistence: Jakub Horák","58'' — Tvrdý pressing Sokol Košetice. Soupeř se nemůže dostat z vlastní půlky.","60'' — Vojtěch Marek v souboji o míč trefil všechno kromě míče.","60'' — Jan Procházka to tam prostě hodil. Nic hezkého, ale funguje to.","60'' — Vojtěch Marek se hádá s rozhodčím. ''Máte to doma trénovat!''","61'' — Filip Procházka to tam prostě hodil. Nic hezkého, ale funguje to.","63'' — Jan Pokorný si stáhl míč patičkou. Pak ale ztratil přehled.","67'' — Slovan Pacov tlačí dopředu. Obrana soupeře má plné ruce práce.","71'' — Slovan Pacov se snaží zrychlit. Zatím marně.","74'' — Rozehrávka od brankáře. Slovan Pacov začínají znovu.","75'' — Střídání — Adam Novotný se konečně dočkal. Sedel na lavičce od začátku.","75'' — Jan Pokorný odkopává z vlastní šestnáctky. Trochu panika.","76'' — Jan Pokorný přihrává do běhu spoluhráči. Dobré načasování.","80'' — Aut pro Slovan Pacov. Chvíle na vydechnutí.","81'' — David Hájek držel soupeře za dres. Tak jednoduchý faul.","82'' — Dělovka od David Hájek! Brankář ani nehnul rukama. To letělo jak z praku.","82'' — Asistence: Jan Pospíšil","82'' — Jakub Horák přihrává do běhu spoluhráči. Dobré načasování.","87'' — Centr od Jan Novák — nikdo se k němu nedostal.","88'' — Přímý kop po faulu Jan Procházka. Soupeř se zvedá ze země.","89'' — Brankář fantasticky zasahuje po ráně Jan Novák! Co to bylo za zákrok!","90'' — Píská se konec! Rozhodčí utíká k autu — pro jistotu."]','{"0a20a38f-8e85-4d49-8855-ecb46ba66c6c":7.2,"66c5d431-39e2-46b4-8dcd-6ac00fbcd7b8":7,"72aae3aa-5fad-4a7b-9bec-c775fa9be59d":6.2,"a521d1fd-5ade-4813-bafb-b9c8b28fd78d":7.5,"5741f560-6546-41f3-a5b1-761481c31009":6.5,"8b269750-3be1-4f99-9bc6-8563288b2aaa":6.2,"86f7d500-4b34-4c76-97e4-6f33e6d020d8":7.2,"7fd24cd4-6aab-4fb5-86aa-8b71d5823939":6.2,"e7b54ffb-427c-4bcd-80e3-2c09fdaddc5e":6.9,"25839b5f-03b6-4798-b9f3-5f322a0ded29":9.5,