INSERT INTO "messages" ("id","conversation_id","sender_type","sender_id","sender_name","body","metadata","sent_at","read") VALUES('a80deb4b-d6ab-41f9-baee-d3975e4bf393','ec6d5dc8-6be9-4b33-9303-c6b98e494b2d','manager','56efc60a-962a-4581-bd6e-9986bdc34f8f','FK KMP Vyškovice','To je jasný',NULL,'2026-04-01T21:15:18.071Z',1);
INSERT INTO "messages" ("id","conversation_id","sender_type","sender_id","sender_name","body","metadata","sent_at","read") VALUES('096cdb12-a6f8-4057-9090-276ec7c65f8a','5a20dac8-f844-474a-bb94-a2b15848267a','system',NULL,'Předseda Přeboru',replace('Vážení trenéři,                                                                                                                                                              \n                                                                                                                                                                               \n  vedení Okresního přeboru Prales na svém zasedání schválilo možnost pořádání přátelských utkání mezi kluby soutěže.                                                           \n                                                                                                                                                                               \n  Kluby mohou od tohoto týdne vyzvat libovolný mančaft vedený lidským trenérem k přátelskému utkání. Výzvu je možné poslat přes sekci Přáteláky v menu. Vyzvaný tým může výzvu \n  přijmout nebo odmítnout. Po přijetí oba trenéři nastaví sestavu a zápas se odehraje v nejbližším zápasovém termínu.                                                          \n                                                            \n  Každý klub hradí náklady na pořádání ve výši 1 000 Kč (rozhodčí, cestovné, značení hřiště). Mezi jednotlivými přáteláky musí uplynout alespoň 3 herní dny. Výsledky          \n  přátelských utkání se nezapočítávají do ligové tabulky, hráči však sbírají cenné herní zkušenosti.\n                                                                                                                                                                               \n  Věříme, že tato novinka přispěje k rozvoji fotbalu v regionu.                                                                                                                \n                                          \n  S pozdravem,                                                                                                                                                                 \n  Kancelář Okresního přeboru Prales','\n',char(10)),NULL,'2026-04-02T11:57:23.379Z',1);
