INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('07bc04ce-c023-48ae-b502-b0f7f05a6791','7a82b469-d4db-4ee6-b730-2ec85a68122d','4f3854db-d146-4d70-8e0d-b0348e90ef91','transfer','Matěj Kuta posílí kádr Jiskra Vlachovo Březí','Matěj Kuta (21, GK) podepsal za Jiskra Vlachovo Březí. Přestupová bomba otřásla okresním fotbalem.',NULL,'2026-03-30 14:11:51');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('9cf30277-c058-4106-a448-4a9dfa4beb86','7a82b469-d4db-4ee6-b730-2ec85a68122d',NULL,'round_results','1. kolo: přehled výsledků','FK Rohde Čkyně porazil Union Litochovice 6:2. Dynamo Dvory porazil Sokol Lhenice 4:2. FK Löffler Spůle porazil Slovan Lenora 6:0. FK Šumavský pivovar Vlachovo Březí porazil Slavoj Horní Vltavice 6:1. FK Koberce Rod Čkyně remizoval s FK Pekařství U Hrocha Bohumilice 2:2. FK Rohde Spůle zvítězil nad Hvězda Záblatí 4:2. Lokomotiva Čkyně porazil Rapid Bavorov 2:0.',1,'2026-03-30 16:15:45');
