INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('0f8c10c5-d571-4c87-abfa-5d0b76426b0c','7a82b469-d4db-4ee6-b730-2ec85a68122d','01f283b9-6e9b-42f0-a214-410175a65a96','manager_arrival','SK Čkyně má nového trenéra: Master Blaster!','Master Blaster přebírá vedení SK Čkyně z Čkyně. V kádru je 20 hráčů, oporami by měli být David Švec (GK, 41), Lukáš Strnad (MID, 39), Tomáš Kopecký (DEF, 38). Fanoušci jsou zvědaví, co přinese nová éra.',NULL,'2026-03-30 18:29:21');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('d67a9f19-bf86-4a24-80bb-50467f2c89eb','7a82b469-d4db-4ee6-b730-2ec85a68122d','79de2314-5751-4b66-ad36-e70e2c7f6605','transfer','Matěj Novák posílí kádr FK Koberce Rod Čkyně','Matěj Novák (24, GK) podepsal za FK Koberce Rod Čkyně. Trenér si mne ruce.',NULL,'2026-03-30 19:21:33');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('9fd273dd-8afd-405e-a05d-b2db1e95be40','7a82b469-d4db-4ee6-b730-2ec85a68122d',NULL,'ai_report','Okresní přebor odstartoval: Čkyně vládne, pivovar to rozjel a Spůle překvapila!',replace('Konečně je to tady! Po dlouhé letní pauze se na zelených trávnících Prachaticka opět rozburácel fotbalový podzim a s ním i první kolo našeho milovaného okresního přeboru. A nutno říct, že úvodní hvizdy rozhodčích přinesly pořádnou porci gólů, napětí a hned několik překvapení!\nNejvětší dominanci hned na úvod předvedla miniaturní šumavská vesnička Spůle. **FK Löffler Spůle**, tenhle malý David s pouhými šedesáti obyvateli, poslal Slovan Lenora s tradicí sklářství domů s pořádným výpraskem 6:0! David Petrášek a Ondřej Veselý si připsali po dvou gólech a ukázali, že i s hrstkou fanoušků (pouhých osm odvážlivců!) se dá hrát fotbal na úrovni.\nMěstečko Čkyně, proslulé gotickým kostelem a řekou Volyňkou, ukázalo hned na úvod, že se na okrese fotbalu pořádně daří. Místní derby mezi **FK Rohde Čkyně** a **SK Čkyně** skončilo divokým výsledkem 6:2. Jakub Hrách a Lukáš Grill řádili na hřišti jako utržení ze řetězu, každý se blýskl dvěma góly a asistencí.\nPravý gólostroj předvedl i Jan Novák z **FK Šumavský pivovar Vlachovo Březí**. Městečko s barokním zámkem a pivovarem z roku 1670 může být na svého střelce náležitě hrdé. Honza si proti Slavoji Horní Vltavice připsal rovnou HATTRICK! Spolu s Janem Novotným, který přidal gól a dvě asistence, dotáhli Vlachovo Březí k drtivému vítězství 6:1.\nZajímavá byla i remíza mezi **FK Koberce Rod Čkyně** a **FK Pekařství U Hrocha Bohumilice**. Obec v podhůří Šumavy se zámkem Skalice ukázala, že se jen tak nevzdá, a odvezla si cenný bod.\nTabulka po prvním kole ukazuje hned šest týmů s plným počtem 3 bodů — boj o čelo bude letos pořádně nabitý. Těšíme se na další kola!','\n',char(10)),1,'2026-03-30 19:59:59');
