INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('6c29c9a5-5b9f-4479-8256-a6938517721f','7a82b469-d4db-4ee6-b730-2ec85a68122d','66ef470e-5cd5-424d-9dbe-7834ad2c416f','manager_arrival','SK Zdíkov má nového trenéra: Krupa!','Krupa přebírá vedení SK Zdíkov z Zdíkov. V kádru je 20 hráčů, oporami by měli být Adam Havel (DEF, 39), Tomáš Musil (MID, 38), Jan Čížek (GK, 38). Fanoušci jsou zvědaví, co přinese nová éra.',NULL,'2026-04-01 07:42:34');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('a7f998f0-e1b9-4cd0-b355-2456d67cb2d2','7a82b469-d4db-4ee6-b730-2ec85a68122d',NULL,'transfer','Přestup! Lukáš Voráček míří z FK Koberce Rod Čkyně do 1.FC Turecká mohutná menšina ve Čkyni s.r.o.','Lukáš Voráček (33, GK) přestupuje z FK Koberce Rod Čkyně do 1.FC Turecká mohutná menšina ve Čkyni s.r.o. za 2 500 Kč. Trenér si mne ruce.',NULL,'2026-04-01 15:44:15');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('c9e1fcdb-353b-4da7-9018-122426ff8a58','7a82b469-d4db-4ee6-b730-2ec85a68122d','79de2314-5751-4b66-ad36-e70e2c7f6605','transfer','Jan Hrubý posílí kádr FK Koberce Rod Čkyně','Jan Hrubý (32, FWD) podepsal za FK Koberce Rod Čkyně. V hospodě se o ničem jiném nemluví.',NULL,'2026-04-01 15:59:16');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('100eea07-737f-46e7-8551-f1aaa95024eb','b655d570-10f5-47d9-b79c-46aee01fd78e',NULL,'round_results','1. kolo: přehled výsledků','Viktoria Černovice zvítězil nad FC Počátky 2:1. Tatran Pelhřimov zvítězil nad Hvězda Červená Řečice 5:1. Meteor Žirovnice porazil TJ Kamenice nad Lipou 2:1. SK Horní Cerekev remizoval s Spartak Lukavec 5:5. Slavoj Senožaty porazil Spartak Humpolec 2:0. Slavoj Vyskytná porazil Sokol Nová Cerekev 2:0. Slovan Pacov porazil Sokol Košetice 6:2. Nejvíce gólů padlo v utkání SK Horní Cerekev vs Spartak Lukavec 5:5.',1,'2026-04-01 16:02:05');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('bc91773c-e418-48ae-aa28-51584b52a0b9','b655d570-10f5-47d9-b79c-46aee01fd78e',NULL,'ai_report','Gólové hody odstartovaly okresní přebor! Pacov se raduje, Cerekev baví remízou',replace('Konečně je to tady! Sluncem zalitá fotbalová hřiště našeho malebného okresu opět ožila a s nimi i tolik očekávané 1. kolo okresního přeboru. A nutno říci, že úvodní dějství nabídlo hned několik parádních představení, spoustu branek a hned dva hattricky!\nNejvětší gólovou smršť předvedl Slovan Pacov, který na domácí půdě nedal šanci sokolu z Košetic a vyprovodil je s náloží 6:2. Hvězdou zápasu se stal náš starý známý Jan Pokorný, který si rovnou připsal hattrick! Tři góly a rating 9.5 – to je vstup do sezóny jako hrom! Pacov se tak hned po prvním kole vyšvihl na čelo tabulky a ukázal, že letos s ním bude nutné počítat.\nPodobně suverénní výkon předvedl i Tatran Pelhřimov, který na hřišti Hvězdy Červená Řečice zvítězil 5:1. I zde se blýskl hattrickem, tentokrát v podání Jana Svobody. Chudáci z Červené Řečice si tak hned na úvod sezóny vybrali černého Petra, ale věříme, že se z toho otřepou a příště ukážou, co v nich dřímá. Osm diváků sice není mnoho, ale ti, co přišli, rozhodně nelitovali.\nAbsolutně nejvíce vzrušení ale přinesl duel SK Horní Cerekev a Spartaku Lukavec. Ti dva se totiž rozhodli, že se s úvodním kolem nebudou mazlit a divákům (bylo jich patnáct, to je na Cerekev slušné!) nabídli neuvěřitelnou přestřelku 5:5! Deset gólů v jednom zápase, to se jen tak nevidí. Tady se skutečně hrálo srdcem a pro radost. I když se po zápase musely zřejmě sbírat míče po celém areálu Horní Cerekve, fanoušci odcházeli nadšení.\nZ ostatních zápasů stojí za zmínku vítězství Slavoj Senožaty nad Spartakem Humpolec 2:0 a stejně tak Slavoj Vyskytná, který porazil Sokol Nová Cerekev rovněž 2:0. Žirovnice si doma poradila s Kamenicí nad Lipou 2:1 a Viktoria Černovice si odvezla těsnou výhru 2:1 z Počátek.\nCelkově nám první kolo naznačilo, že nás čeká napínavá sezóna plná branek a emocí. Tabulka je zatím samozřejmě jen zahřívací kolo, ale už teď se těšíme na další fotbalové zážitky, které nám náš okresní přebor přinese. A hlavně – ať se nám všem daří!','\n',char(10)),1,'2026-04-01 16:02:12');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('d86f6a75-41c8-486d-bb91-bb544ef97e5b','7a82b469-d4db-4ee6-b730-2ec85a68122d','79de2314-5751-4b66-ad36-e70e2c7f6605','transfer','FK Koberce Rod Čkyně nabízí Michal Petrášek na přestup','Na přestupovém trhu se objevil Michal Petrášek (36, FWD) z FK Koberce Rod Čkyně. Požadovaná cena: 1 000 Kč.',NULL,'2026-04-01 16:03:47');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('8ac87112-118d-40b6-8baa-ddb90d7bb205','1834505d-e74b-4891-9c24-a4c395b8f3bf',NULL,'round_results','2. kolo: přehled výsledků','SK Pardubice porazil FK Zetor Tractors Pardubice 5:1. Nejvíce gólů padlo v utkání SK Pardubice vs FK Zetor Tractors Pardubice 5:1.',2,'2026-04-02 16:00:46');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('dc8d4d86-aff5-46c9-b681-230ca326a07c','1834505d-e74b-4891-9c24-a4c395b8f3bf',NULL,'ai_report','Pardubické derby: Kanonáda na východě Čech zamíchala tabulkou!',replace('Vážení fotbaloví přátelé a příznivci kopané v Prachaticích a okolí! Zatímco u nás pod Boubínem si pomalu zvykáme na první podzimní mlhy a vůni dřeva z krbů, na východě Čech to v sobotu pořádně vřelo. Druhé kolo okresního přeboru sice nás, šumavské patrioty, přímo nezasáhlo, ale přineslo výsledek, který stojí za to se o něm rozepsat. A věřte mi, že i v hospůdce U Dvou lip v Husinci se o tom bude živě diskutovat!\nHlavní událostí kola bylo bezesporu pardubické derby, které se odehrálo na Sportovním areálu Pardubice. Proti sobě se postavily týmy SK Pardubice a FK Zetor Tractors Pardubice. A že to byla jízda, to vám povím! Domácí SK Pardubice předvedli parádní kanonádu a smetli Zetor Tractors poměrem 5:1. Před tisícovkou diváků, což je na okresní přebor v Pardubicích slušná návštěva, padaly góly jako z automatu. Už v 9. minutě otevřel skóre Matěj Černý a ukázal, že má formu. Do poločasu ještě přidal gól Lukáš Marek a zdálo se, že je hotovo.\nAle co se dělo ve druhé půli, to bylo něco! Mezi 61. a 65. minutou to tam sypalo jeden za druhým. David Dvořák, Tomáš Novotný a Filip Dvořák, ten dokonce s ratingem 8.1 a jednou asistencí, během pouhých čtyř minut poslali Zetor Tractors do kolen. Čestný úspěch hostů zaznamenal Lukáš Pospíšil v 83. minutě, a i on si vysloužil parádní rating 8.1 a jednu asistenci. No, i přes prohru zanechal dojem!\nDíky tomuto výsledku se nám tabulka po 2. kole pěkně zamíchala. SK Pardubice sice mají stejně bodů jako FK Zetor Tractors Pardubice, tedy 3 body, ale díky lepšímu skóre 6:6 se posunuli na první místo. Zetor Tractors naopak klesli na druhé místo. Je vidět, že i v Pardubicích se hraje fotbal se spádem a na góly se nešetří.\nTakže si to shrňme: Filip Dvořák a Lukáš Pospíšil z SK Pardubic byli s ratingem 8.1 hvězdami zápasu, a Matěj Černý, který otevřel skóre, také nezůstal pozadu. Dvě žluté karty pro Tomáše Šťastného a Jakuba Krále z hostujícího týmu svědčí o tom, že se hrálo s nasazením.\nMy si tady v Prachaticích můžeme jen povzdechnout, že takové gólové hody u nás zatím nebyly k vidění. Ale nebojte, věřím, že i naše týmy z Netolic, Volar nebo Vimperka nám brzy předvedou něco podobného. Zůstaňte naladěni na další zprávy z okresního fotbalu!','\n',char(10)),2,'2026-04-02 16:00:53');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('4a6294ef-41e3-4947-9a86-1eac094d72c6','7a82b469-d4db-4ee6-b730-2ec85a68122d',NULL,'round_results','2. kolo: přehled výsledků','FK Rohde Čkyně zvítězil nad FK KMP Vyškovice 5:1. FK Löffler Volary porazil SK Čkyně 6:5. FK Löffler Zdíkov remizoval s FK Löffler Hradčany 2:2. FK Löffler Spůle zvítězil nad FK Pekařství U Hrocha Bohumilice 1:0. FK Rohde Spůle remizoval s FK Šumavský pivovar Vlachovo Březí 2:2. FK Koberce Rod Čkyně zvítězil nad Rapid Bavorov 2:0. 1.FC Turecká mohutná menšina ve Čkyni s.r.o. zvítězil nad Lokomotiva Čkyně 2:1. Nejvíce gólů padlo v utkání FK Löffler Volary vs SK Čkyně 6:5.',2,'2026-04-02 16:03:39');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('fe64f9cc-df38-4f00-a902-3e35a7908959','7a82b469-d4db-4ee6-b730-2ec85a68122d',NULL,'ai_report','Fotbalové odpoledne pod Šumavou: Čkyně vládne, Volary překvapují a Zdíkov boduje i bez výhry!',replace('Druhé kolo okresního přeboru je za námi a fotbalová Šumava opět ukázala, že umí bavit! I přes zataženou oblohu, která nad naším malebným krajem visela celý víkend, se diváci dočkali pořádné porce gólů a překvapivých výsledků.\nNejvětší pozornost na sebe strhla opět Čkyně, a to hned několikrát! FK Rohde Čkyně si to namířil do Vyškovic a nenechal nic náhodě. Rozjeli se hned od první minuty, když Jakub Černý poslal míč do sítě. A tenhle "Černej" den pro Vyškovice pokračoval! Jakub Černý se blýskl rovnou hattrickem a jeho tým si s přehledem odvezl vítězství 5:1. Tři góly, to je vizitka! Nicméně, radost kazí červená karta pro Jana Kubičku, což je pro Rohde do dalších bojů nepříjemná komplikace.\nAbsolutní gólová smršť se pak odehrála ve Volarech, v podhůří Šumavy, kde FK Löffler Volary hostil SK Čkyně. Co vám budu povídat, to byl zápas pro fotbalové gurmány! Utkání skončilo divokým skóre 6:5 pro domácí Volary, což je na Rohde Areně pořádná rarita! Diváci si přišli na své, viděli jedenáct gólů a nervy drásající závěr, kdy Volary otočily zápas v posledních minutách. Jan Krejčí v 89. minutě rozhodl o překvapivém vítězství a Volary se rázem vyšvihly v tabulce. Filip Záhora ze SK Čkyně si sice připsal hattrick, ale jeho tým si i přes takový výkon body neodvezl. Škoda pro malebné městečko na Volyňce!\nZajímavou bitvu svedly i celky FK Löffler Zdíkov a FK Löffler Hradčany na Truhlářství Koška Areně. Zdíkov, známý svou dřevařskou tradicí, dokázal na domácí půdě uhrát remízu 2:2, i když to chvíli vypadalo na prohru. Tomáš Černý zachraňoval bod pro Zdíkov v 83. minutě a ukázal, že tým má bojovného ducha.\nV Bohumilicích, u řeky Volyňky, kde se tyčí zámek Skalice, se domácímu Pekařství U Hrocha nepodařilo vstřelit ani gól a podlehlo Spůli 0:1. Jediný gól Filipa Pribyla v 58. minutě stačil k vítězství pro malou šumavskou vesničku s 60 obyvateli. Ukazuje se, že i malé týmy umí překvapit!\nPo druhém kole se na čele tabulky usadil FK Rohde Čkyně s plným počtem šesti bodů, následovaný FK Löffler Spůle, taktéž s šesti body. Šumavský pivovar Vlachovo Březí si drží třetí místo se čtyřmi body. Na chvostu tabulky se bohužel drží FK KMP Vyškovice a SK Čkyně, oba týmy zatím bez bodu. Uvidíme, jak se s tím poperou v dalších kolech! Jakub Černý z Rohde Čkyně si s ratingem 9.5 zaslouží potlesk za svůj vynikající výkon. Okresní přebor je zkrátka plný překvapení a my se už těšíme na další kolo!','\n',char(10)),2,'2026-04-02 16:03:47');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('d657ae1c-e035-4e76-a40b-deec7f427285','7a82b469-d4db-4ee6-b730-2ec85a68122d','44e88dfe-6000-4d3e-a6c5-980eec6be216','transfer','David Tesař posílí kádr FK Löffler Spůle','David Tesař (37, MID) podepsal za FK Löffler Spůle. Trenér si mne ruce.',NULL,'2026-04-03 01:37:45');
