INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(115,'special','Trenér kopnul do láhve s vodou. Frustrace roste.','["funny"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(116,'special','{player} si povídá s divákem u plotu. Rozhodčí ho napomíná.','["funny"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(117,'special','Někdo hodil na hřiště rohlík. Asi protest.','["crowd","funny"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(118,'special','Začalo pršet. Polovina diváků utekla pod střechu hospody.','["atmosphere"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(119,'special','{player} si stěžuje, že ho spoluhráči nevidí. Asi má pravdu.','["funny"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(120,'special','Na lavičce se řeší, kdo zaplatí rozhodčímu.','["funny"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(121,'special','{team} kombinují přes střed hřiště.','["possession"]',0,'2026-03-28 21:33:10');
