INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(123,'special','Tvrdý pressing {team}. Soupeř se nemůže dostat z vlastní půlky.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(124,'special','{player} rozehrává z hloubky pole.','["possession"]',0,'2026-03-28 21:33:10');
