INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(126,'special','Soupeř stahuje obranu, {team} hledají prostor.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(127,'special','Dlouhý míč od {player}, {team} zrychlují.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(128,'special','Hra se přesouvá na polovinu soupeře.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(129,'special','{team} mají míč. Zatím nic nebezpečného.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(130,'special','{player} vede míč po křídle. Hledá přihrávku.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(131,'special','{team} pomalu budují útok. Trpělivá hra.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(132,'special','{player} nahrává do středu — míč se vrací do obrany.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(133,'special','Rozehrávka od brankáře. {team} začínají znovu.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(134,'special','{team} tlačí dopředu. Obrana soupeře má plné ruce práce.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(135,'special','{player} se snaží projít přes dva hráče. Neúspěšně.','["possession"]',0,'2026-03-28 21:33:10');
