PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE villages (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  district TEXT NOT NULL,
  region TEXT NOT NULL,
  population INTEGER NOT NULL,
  size TEXT NOT NULL CHECK(size IN ('hamlet','village','town','small_city','city')),
  lat REAL NOT NULL,
  lng REAL NOT NULL
);
CREATE TABLE users (
  id TEXT PRIMARY KEY,
  email TEXT UNIQUE NOT NULL,
  password_hash TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
, display_name TEXT, is_admin INTEGER NOT NULL DEFAULT 0);
CREATE TABLE teams (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL REFERENCES users(id),
  village_id TEXT NOT NULL REFERENCES villages(id),
  name TEXT NOT NULL,
  primary_color TEXT NOT NULL DEFAULT '#2D5F2D',
  secondary_color TEXT NOT NULL DEFAULT '#FFFFFF',
  budget INTEGER NOT NULL DEFAULT 40000,
  reputation INTEGER NOT NULL DEFAULT 50,
  league_id TEXT,
  naming_sponsor_id TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
, jersey_pattern TEXT NOT NULL DEFAULT 'solid', badge_pattern TEXT NOT NULL DEFAULT 'shield', stadium_name TEXT, training_type TEXT DEFAULT 'conditioning', training_approach TEXT DEFAULT 'balanced', training_sessions INTEGER DEFAULT 2, last_training_at TEXT, last_training_result TEXT, captain_id TEXT REFERENCES players(id), penalty_taker_id TEXT REFERENCES players(id), freekick_taker_id TEXT REFERENCES players(id), last_main_sponsor_change_season INTEGER DEFAULT 0, game_date TEXT, season_start TEXT, season_end TEXT);
CREATE TABLE players (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL REFERENCES teams(id),
  first_name TEXT NOT NULL,
  last_name TEXT NOT NULL,
  nickname TEXT NOT NULL DEFAULT '',
  age INTEGER NOT NULL,
  position TEXT NOT NULL CHECK(position IN ('GK','DEF','MID','FWD')),
  overall_rating INTEGER NOT NULL,
  skills TEXT NOT NULL,           
  physical TEXT NOT NULL,         
  personality TEXT NOT NULL,      
  life_context TEXT NOT NULL,     
  avatar TEXT NOT NULL,           
  description TEXT NOT NULL DEFAULT '',
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
, skills_max TEXT NOT NULL DEFAULT '{}', gk_skills TEXT NOT NULL DEFAULT '{}', gk_skills_max TEXT NOT NULL DEFAULT '{}', hidden_talent INTEGER NOT NULL DEFAULT 0, experience INTEGER NOT NULL DEFAULT 0, residence TEXT, commute_km INTEGER DEFAULT 0, weekly_wage INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL DEFAULT 'active', squad_number INTEGER, loan_from_team_id TEXT, loan_until TEXT, suspended_matches INTEGER NOT NULL DEFAULT 0);
CREATE TABLE season_calendar (
  id TEXT PRIMARY KEY,
  league_id TEXT NOT NULL,
  season_number INTEGER NOT NULL,
  game_week INTEGER NOT NULL,
  match_day TEXT NOT NULL CHECK(match_day IN ('wednesday','saturday','sunday')),
  scheduled_at TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'scheduled' CHECK(status IN ('scheduled','lineup_locked','simulated'))
);
CREATE TABLE lineups (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL REFERENCES teams(id),
  calendar_id TEXT NOT NULL REFERENCES season_calendar(id),
  formation TEXT NOT NULL DEFAULT '4-4-2',
  tactic TEXT NOT NULL DEFAULT 'balanced',
  players_data TEXT NOT NULL DEFAULT '[]',
  submitted_at TEXT,
  is_auto INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE matches (
  id TEXT PRIMARY KEY,
  league_id TEXT,                     
  calendar_id TEXT REFERENCES season_calendar(id),
  round INTEGER,
  home_team_id TEXT NOT NULL REFERENCES teams(id),
  away_team_id TEXT NOT NULL REFERENCES teams(id),
  home_lineup_id TEXT REFERENCES lineups(id),
  away_lineup_id TEXT REFERENCES lineups(id),
  home_score INTEGER,
  away_score INTEGER,
  status TEXT NOT NULL DEFAULT 'scheduled' CHECK(status IN ('scheduled','lineups_open','simulated')),
  events TEXT,                        
  commentary TEXT,                    
  player_ratings TEXT,                
  simulated_at TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
, home_seen_at TEXT, away_seen_at TEXT, attendance INTEGER, stadium_name TEXT, pitch_condition INTEGER, weather TEXT, home_lineup_data TEXT, away_lineup_data TEXT, absences TEXT);
CREATE TABLE challenges (
  id TEXT PRIMARY KEY,
  challenger_team_id TEXT NOT NULL REFERENCES teams(id),
  challenged_team_id TEXT NOT NULL REFERENCES teams(id),
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','accepted','declined','expired','played')),
  match_id TEXT REFERENCES matches(id),
  message TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  expires_at TEXT NOT NULL
);
CREATE TABLE chat_messages (
  id TEXT PRIMARY KEY,
  league_id TEXT NOT NULL,
  team_id TEXT NOT NULL REFERENCES teams(id),
  team_name TEXT NOT NULL,
  message TEXT NOT NULL,
  is_system INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE notifications (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL REFERENCES teams(id),
  type TEXT NOT NULL CHECK(type IN ('match_reminder','match_result','event','challenge','transfer','season','system')),
  title TEXT NOT NULL,
  body TEXT NOT NULL,
  read INTEGER NOT NULL DEFAULT 0,
  action_url TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE cups (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  district TEXT NOT NULL,
  season TEXT NOT NULL,
  type TEXT NOT NULL CHECK(type IN ('district_cup','regional_cup','winter_tournament','friendly_tournament')),
  status TEXT NOT NULL DEFAULT 'registration' CHECK(status IN ('registration','in_progress','finished')),
  bracket TEXT,                       
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE cup_entries (
  id TEXT PRIMARY KEY,
  cup_id TEXT NOT NULL REFERENCES cups(id),
  team_id TEXT NOT NULL REFERENCES teams(id),
  seed INTEGER,
  eliminated INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE seasonal_events (
  id TEXT PRIMARY KEY,
  league_id TEXT NOT NULL,
  type TEXT NOT NULL CHECK(type IN ('zabijacka','ples','vanocni_turnaj','silvestr','letni_soustredeni','obecni_zpravodaj')),
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  effects TEXT NOT NULL,              
  choices TEXT,                       
  season TEXT NOT NULL,
  game_week INTEGER NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','active','resolved')),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE managers (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL REFERENCES users(id),
  team_id TEXT REFERENCES teams(id),
  name TEXT NOT NULL,
  backstory TEXT NOT NULL,
  avatar TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
, age INTEGER, coaching INTEGER NOT NULL DEFAULT 40, motivation INTEGER NOT NULL DEFAULT 40, tactics INTEGER NOT NULL DEFAULT 40, youth_development INTEGER NOT NULL DEFAULT 40, discipline INTEGER NOT NULL DEFAULT 40, reputation INTEGER NOT NULL DEFAULT 30, bio TEXT, birthplace TEXT);
CREATE TABLE seasons (
  id TEXT PRIMARY KEY,
  number INTEGER NOT NULL UNIQUE,
  status TEXT NOT NULL DEFAULT 'active' CHECK(status IN ('active','winter_break','finished')),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE leagues (
  id TEXT PRIMARY KEY,
  season_id TEXT NOT NULL REFERENCES seasons(id),
  district TEXT NOT NULL,
  name TEXT NOT NULL,
  level TEXT NOT NULL DEFAULT 'okresni_prebor' CHECK(level IN ('okresni_soutez','okresni_prebor','ib_trida','ia_trida','krajsky_prebor')),
  status TEXT NOT NULL DEFAULT 'active' CHECK(status IN ('active','finished')),
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE(season_id, district, level)
);
CREATE TABLE league_history (
  id TEXT PRIMARY KEY,
  league_id TEXT NOT NULL REFERENCES leagues(id),
  final_standings TEXT NOT NULL,
  promotions TEXT,
  relegations TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE conversations (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL REFERENCES teams(id),
  type TEXT NOT NULL CHECK(type IN ('squad_group','player','manager','system')),
  title TEXT NOT NULL,
  participant_id TEXT,             
  participant_avatar TEXT,         
  last_message_text TEXT,
  last_message_at TEXT,
  unread_count INTEGER NOT NULL DEFAULT 0,
  pinned INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE messages (
  id TEXT PRIMARY KEY,
  conversation_id TEXT NOT NULL REFERENCES conversations(id),
  sender_type TEXT NOT NULL CHECK(sender_type IN ('player','manager','system','user')),
  sender_id TEXT,                  
  sender_name TEXT NOT NULL,
  body TEXT NOT NULL,
  metadata TEXT,                   
  sent_at TEXT NOT NULL DEFAULT (datetime('now')),
  read INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE player_stats (
  id TEXT PRIMARY KEY,
  player_id TEXT NOT NULL REFERENCES players(id),
  team_id TEXT NOT NULL REFERENCES teams(id),
  season_id TEXT NOT NULL REFERENCES seasons(id),
  appearances INTEGER NOT NULL DEFAULT 0,
  goals INTEGER NOT NULL DEFAULT 0,
  assists INTEGER NOT NULL DEFAULT 0,
  yellow_cards INTEGER NOT NULL DEFAULT 0,
  red_cards INTEGER NOT NULL DEFAULT 0,
  man_of_match INTEGER NOT NULL DEFAULT 0,
  minutes_played INTEGER NOT NULL DEFAULT 0,
  avg_rating REAL NOT NULL DEFAULT 0,
  clean_sheets INTEGER NOT NULL DEFAULT 0,   
  UNIQUE(player_id, season_id)
);
CREATE TABLE injuries (
  id TEXT PRIMARY KEY,
  player_id TEXT NOT NULL REFERENCES players(id),
  team_id TEXT NOT NULL REFERENCES teams(id),
  type TEXT NOT NULL CHECK(type IN ('sval','kotnік','koleno','zada','hlava','zebra','achilovka','tříselný','rameno','obecne')),
  description TEXT NOT NULL,
  severity TEXT NOT NULL CHECK(severity IN ('lehke','stredni','tezke')),
  days_remaining INTEGER NOT NULL,         
  days_total INTEGER NOT NULL,             
  match_id TEXT REFERENCES matches(id),    
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE stadiums (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL UNIQUE REFERENCES teams(id),
  capacity INTEGER NOT NULL DEFAULT 200,
  pitch_condition INTEGER NOT NULL DEFAULT 50,   
  pitch_type TEXT NOT NULL DEFAULT 'natural' CHECK(pitch_type IN ('natural','hybrid','artificial')),

  
  changing_rooms INTEGER NOT NULL DEFAULT 1,
  showers INTEGER NOT NULL DEFAULT 1,
  refreshments INTEGER NOT NULL DEFAULT 0,        
  lighting INTEGER NOT NULL DEFAULT 0,            
  stands INTEGER NOT NULL DEFAULT 0,              
  parking INTEGER NOT NULL DEFAULT 0,             
  fence INTEGER NOT NULL DEFAULT 0,               

  created_at TEXT NOT NULL DEFAULT (datetime('now'))
, upgrade_facility TEXT, upgrade_completes_at TEXT);
CREATE TABLE equipment (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL UNIQUE REFERENCES teams(id),
  balls INTEGER NOT NULL DEFAULT 0,
  jerseys INTEGER NOT NULL DEFAULT 0,
  training_cones INTEGER NOT NULL DEFAULT 0,
  first_aid INTEGER NOT NULL DEFAULT 0,
  boots_stock INTEGER NOT NULL DEFAULT 0,
  bibs INTEGER NOT NULL DEFAULT 0,
  balls_condition INTEGER NOT NULL DEFAULT 50,
  jerseys_condition INTEGER NOT NULL DEFAULT 50,
  training_cones_condition INTEGER NOT NULL DEFAULT 50,
  first_aid_condition INTEGER NOT NULL DEFAULT 50,
  boots_stock_condition INTEGER NOT NULL DEFAULT 50,
  bibs_condition INTEGER NOT NULL DEFAULT 50,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
, goalkeeper_gear INTEGER NOT NULL DEFAULT 0, water_bottles INTEGER NOT NULL DEFAULT 0, tactics_board INTEGER NOT NULL DEFAULT 0, goalkeeper_gear_condition INTEGER NOT NULL DEFAULT 50, water_bottles_condition INTEGER NOT NULL DEFAULT 50, tactics_board_condition INTEGER NOT NULL DEFAULT 50, upgrade_category TEXT, upgrade_completes_at TEXT);
CREATE TABLE IF NOT EXISTS "relationships" (
  id TEXT PRIMARY KEY,
  player_a_id TEXT NOT NULL REFERENCES players(id),
  player_b_id TEXT NOT NULL REFERENCES players(id),
  type TEXT NOT NULL CHECK(type IN ('brothers','father_son','in_laws','classmates','coworkers','neighbors','drinking_buddies','rivals','mentor_pupil')),
  strength INTEGER NOT NULL DEFAULT 50
);
CREATE TABLE district_surnames (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  district TEXT NOT NULL,
  surname TEXT NOT NULL,
  frequency INTEGER NOT NULL,
  UNIQUE(district, surname)
);
CREATE TABLE district_sponsors (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  district TEXT NOT NULL,
  name TEXT NOT NULL,
  type TEXT NOT NULL,
  monthly_min INTEGER NOT NULL,
  monthly_max INTEGER NOT NULL,
  win_bonus_min INTEGER NOT NULL,
  win_bonus_max INTEGER NOT NULL
);
CREATE TABLE sponsor_contracts (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL REFERENCES teams(id),
  sponsor_name TEXT NOT NULL,
  sponsor_type TEXT NOT NULL,
  monthly_amount INTEGER NOT NULL,
  win_bonus INTEGER NOT NULL DEFAULT 0,
  seasons_total INTEGER NOT NULL DEFAULT 1,    
  seasons_remaining INTEGER NOT NULL DEFAULT 1,
  early_termination_fee INTEGER NOT NULL DEFAULT 0,  
  is_naming_rights INTEGER NOT NULL DEFAULT 0,       
  status TEXT NOT NULL DEFAULT 'active' CHECK(status IN ('active','expired','terminated')),
  signed_at TEXT NOT NULL DEFAULT (datetime('now'))
, category TEXT NOT NULL DEFAULT 'main' CHECK(category IN ('main','stadium')));
CREATE TABLE news (
  id TEXT PRIMARY KEY,
  league_id TEXT NOT NULL,
  team_id TEXT,
  type TEXT NOT NULL,
  headline TEXT NOT NULL,
  body TEXT NOT NULL,
  game_week INTEGER,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE match_player_stats (
  id TEXT PRIMARY KEY,
  match_id TEXT NOT NULL,
  player_id TEXT NOT NULL,
  team_id TEXT NOT NULL,
  started INTEGER NOT NULL DEFAULT 1,
  position TEXT NOT NULL DEFAULT 'MID',
  minutes_played INTEGER NOT NULL DEFAULT 90,
  goals INTEGER NOT NULL DEFAULT 0,
  assists INTEGER NOT NULL DEFAULT 0,
  yellow_cards INTEGER NOT NULL DEFAULT 0,
  red_cards INTEGER NOT NULL DEFAULT 0,
  rating REAL NOT NULL DEFAULT 6.0,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE(match_id, player_id)
);
CREATE TABLE player_contracts (
  id TEXT PRIMARY KEY,
  player_id TEXT NOT NULL,
  team_id TEXT NOT NULL,
  season_id TEXT NOT NULL,
  joined_at TEXT NOT NULL DEFAULT (datetime('now')),
  left_at TEXT,
  join_type TEXT NOT NULL DEFAULT 'generated',  
  leave_type TEXT,                                
  fee INTEGER DEFAULT 0,
  is_active INTEGER NOT NULL DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE classifieds (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL,
  team_name TEXT NOT NULL,
  league_id TEXT,
  category TEXT NOT NULL DEFAULT 'general',  
  message TEXT NOT NULL,
  cost INTEGER NOT NULL DEFAULT 500,
  expires_at TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE transactions (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL,
  type TEXT NOT NULL,
  amount INTEGER NOT NULL,
  balance_after INTEGER NOT NULL,
  description TEXT NOT NULL,
  reference_id TEXT,
  game_date TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE training_log (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  player_id TEXT NOT NULL REFERENCES players(id) ON DELETE CASCADE,
  team_id TEXT NOT NULL,
  attribute TEXT NOT NULL,
  old_value INTEGER NOT NULL,
  new_value INTEGER NOT NULL,
  change INTEGER NOT NULL,
  training_type TEXT NOT NULL,
  game_date TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE free_agents (
  id TEXT PRIMARY KEY,
  district TEXT NOT NULL,
  first_name TEXT NOT NULL,
  last_name TEXT NOT NULL,
  nickname TEXT,
  age INTEGER NOT NULL,
  position TEXT NOT NULL CHECK(position IN ('GK','DEF','MID','FWD')),
  overall_rating INTEGER NOT NULL DEFAULT 50,
  skills TEXT NOT NULL DEFAULT '{}',
  physical TEXT NOT NULL DEFAULT '{}',
  personality TEXT NOT NULL DEFAULT '{}',
  life_context TEXT NOT NULL DEFAULT '{}',
  avatar TEXT NOT NULL DEFAULT '{}',
  hidden_talent REAL DEFAULT 0,
  description TEXT NOT NULL DEFAULT '',
  weekly_wage INTEGER NOT NULL DEFAULT 0,
  source TEXT NOT NULL DEFAULT 'generated' CHECK(source IN ('generated','released','quit')),
  released_from_team_id TEXT,
  village_id TEXT,
  rejected_by TEXT NOT NULL DEFAULT '[]',
  expires_at TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE transfer_offers (
  id TEXT PRIMARY KEY,
  player_id TEXT NOT NULL,
  from_team_id TEXT NOT NULL,
  to_team_id TEXT NOT NULL,
  offer_amount INTEGER NOT NULL,
  counter_amount INTEGER,
  message TEXT,
  reject_message TEXT,
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK(status IN ('pending','accepted','rejected','countered','withdrawn','expired')),
  expires_at TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  resolved_at TEXT
, offer_type TEXT NOT NULL DEFAULT 'transfer'
  CHECK(offer_type IN ('transfer', 'loan')), loan_duration INTEGER);
CREATE TABLE transfer_listings (
  id TEXT PRIMARY KEY,
  player_id TEXT NOT NULL,
  team_id TEXT NOT NULL,
  asking_price INTEGER NOT NULL,
  league_id TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'active'
    CHECK(status IN ('active','sold','withdrawn','expired')),
  expires_at TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE transfer_bids (
  id TEXT PRIMARY KEY,
  listing_id TEXT NOT NULL,
  team_id TEXT NOT NULL,
  amount INTEGER NOT NULL,
  message TEXT,
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK(status IN ('pending','accepted','rejected','withdrawn')),
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE commentary_templates (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  event_type TEXT NOT NULL,         
  template TEXT NOT NULL,
  tags TEXT NOT NULL DEFAULT '[]',  
  min_skill INTEGER DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE crowd_reactions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  text TEXT NOT NULL
);
CREATE TABLE player_offers (
  id TEXT PRIMARY KEY,
  team_id TEXT NOT NULL,
  source TEXT NOT NULL CHECK(source IN ('youth', 'friend', 'pub', 'recommendation')),
  source_name TEXT NOT NULL,  
  message TEXT NOT NULL,      
  
  first_name TEXT NOT NULL,
  last_name TEXT NOT NULL,
  nickname TEXT,
  age INTEGER NOT NULL,
  position TEXT NOT NULL CHECK(position IN ('GK','DEF','MID','FWD')),
  overall_rating INTEGER NOT NULL,
  skills TEXT NOT NULL DEFAULT '{}',
  physical TEXT NOT NULL DEFAULT '{}',
  personality TEXT NOT NULL DEFAULT '{}',
  life_context TEXT NOT NULL DEFAULT '{}',
  avatar TEXT NOT NULL DEFAULT '{}',
  weekly_wage INTEGER NOT NULL DEFAULT 0,
  
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','accepted','rejected','expired')),
  expires_at TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_villages_region ON villages(region);
CREATE INDEX idx_villages_district ON villages(district);
CREATE INDEX idx_players_team ON players(team_id);
CREATE INDEX idx_calendar_league ON season_calendar(league_id);
CREATE INDEX idx_calendar_scheduled ON season_calendar(scheduled_at);
CREATE INDEX idx_lineups_team ON lineups(team_id);
CREATE INDEX idx_lineups_calendar ON lineups(calendar_id);
CREATE INDEX idx_matches_home ON matches(home_team_id);
CREATE INDEX idx_matches_away ON matches(away_team_id);
CREATE INDEX idx_matches_calendar ON matches(calendar_id);
CREATE INDEX idx_matches_status ON matches(status);
CREATE INDEX idx_challenges_challenger ON challenges(challenger_team_id);
CREATE INDEX idx_challenges_challenged ON challenges(challenged_team_id);
CREATE INDEX idx_challenges_status ON challenges(status);
CREATE INDEX idx_chat_league ON chat_messages(league_id);
CREATE INDEX idx_chat_created ON chat_messages(created_at);
CREATE INDEX idx_notifications_team ON notifications(team_id);
CREATE INDEX idx_notifications_unread ON notifications(team_id, read);
CREATE INDEX idx_cup_entries_cup ON cup_entries(cup_id);
CREATE INDEX idx_seasonal_league ON seasonal_events(league_id);
CREATE INDEX idx_managers_user ON managers(user_id);
CREATE INDEX idx_managers_team ON managers(team_id);
CREATE INDEX idx_leagues_season ON leagues(season_id);
CREATE INDEX idx_leagues_district ON leagues(district);
CREATE INDEX idx_conv_team ON conversations(team_id);
CREATE INDEX idx_conv_team_type ON conversations(team_id, type);
CREATE INDEX idx_conv_last ON conversations(team_id, last_message_at);
CREATE INDEX idx_msg_conv ON messages(conversation_id);
CREATE INDEX idx_msg_conv_time ON messages(conversation_id, sent_at);
CREATE INDEX idx_msg_unread ON messages(conversation_id, read);
CREATE INDEX idx_player_stats_player ON player_stats(player_id);
CREATE INDEX idx_player_stats_team ON player_stats(team_id);
CREATE INDEX idx_player_stats_season ON player_stats(season_id);
CREATE INDEX idx_player_stats_goals ON player_stats(season_id, goals DESC);
CREATE INDEX idx_injuries_player ON injuries(player_id);
CREATE INDEX idx_injuries_team ON injuries(team_id);
CREATE INDEX idx_injuries_active ON injuries(team_id, days_remaining);
CREATE INDEX idx_stadiums_team ON stadiums(team_id);
CREATE INDEX idx_equipment_team ON equipment(team_id);
CREATE INDEX idx_relationships_a ON relationships(player_a_id);
CREATE INDEX idx_relationships_b ON relationships(player_b_id);
CREATE INDEX idx_district_surnames ON district_surnames(district);
CREATE INDEX idx_district_sponsors ON district_sponsors(district);
CREATE INDEX idx_sponsor_contracts_team ON sponsor_contracts(team_id);
CREATE INDEX idx_sponsor_contracts_active ON sponsor_contracts(team_id, status);
CREATE INDEX idx_mps_player ON match_player_stats(player_id);
CREATE INDEX idx_mps_match ON match_player_stats(match_id);
CREATE INDEX idx_mps_team ON match_player_stats(team_id);
CREATE INDEX idx_pc_player ON player_contracts(player_id);
CREATE INDEX idx_pc_team ON player_contracts(team_id);
CREATE INDEX idx_pc_active ON player_contracts(player_id, is_active);
CREATE INDEX idx_classifieds_league ON classifieds(league_id);
CREATE INDEX idx_classifieds_team ON classifieds(team_id);
CREATE INDEX idx_txn_team ON transactions(team_id);
CREATE INDEX idx_txn_team_date ON transactions(team_id, game_date);
CREATE INDEX idx_txn_team_type ON transactions(team_id, type);
CREATE INDEX idx_training_log_player ON training_log(player_id);
CREATE INDEX idx_training_log_team ON training_log(team_id);
CREATE INDEX idx_fa_district ON free_agents(district);
CREATE INDEX idx_fa_expires ON free_agents(expires_at);
CREATE INDEX idx_to_from ON transfer_offers(from_team_id, status);
CREATE INDEX idx_to_to ON transfer_offers(to_team_id, status);
CREATE INDEX idx_tl_league ON transfer_listings(league_id, status);
CREATE INDEX idx_tl_team ON transfer_listings(team_id);
CREATE INDEX idx_tb_listing ON transfer_bids(listing_id, status);
CREATE INDEX idx_tb_team ON transfer_bids(team_id);
CREATE INDEX idx_ct_type ON commentary_templates(event_type);
CREATE INDEX idx_po_team ON player_offers(team_id, status);
